import{_ as t,c as e,o as a,a4 as o}from"./chunks/framework.I1cCAST3.js";const l="/assets/autocomplete.BTzq9NVD.png",g=JSON.parse('{"title":"命令补全","description":"","frontmatter":{},"headers":[],"relativePath":"docs/terminal/autocomplete/index.md","filePath":"docs/terminal/autocomplete/index.md"}'),r={name:"docs/terminal/autocomplete/index.md"},d=o('<h1 id="命令补全" tabindex="-1">命令补全 <a class="header-anchor" href="#命令补全" aria-label="Permalink to &quot;命令补全&quot;">​</a></h1><p>Chaterm 在终端输入时自动提供命令建议，通过历史记录、内置命令库和可选的 AI 建议帮助您更快地工作并减少输入错误。</p><p><img src="'+l+'" alt=""></p><h2 id="工作原理" tabindex="-1">工作原理 <a class="header-anchor" href="#工作原理" aria-label="Permalink to &quot;工作原理&quot;">​</a></h2><p>命令补全综合以下三个来源生成建议：</p><ul><li><strong>历史命令</strong> -- 优先推荐当前服务器使用过的命令，同时补充您在其他服务器上常用的命令（跨主机推荐）。</li><li><strong>内置命令库</strong> -- 常见的 Linux 和 Shell 命令始终作为建议可用。</li><li><strong>AI 智能建议（可选）</strong> -- 基于当前输入生成上下文感知的命令补全。</li></ul><p>跨主机推荐会优先匹配当前服务器的使用习惯，再补充您在其他服务器上常用的相关命令。</p><h2 id="使用方式" tabindex="-1">使用方式 <a class="header-anchor" href="#使用方式" aria-label="Permalink to &quot;使用方式&quot;">​</a></h2><ol><li>在终端中开始输入命令，补全面板会自动出现。</li><li>按 <code>→</code>（右箭头）进入选择模式。</li><li>按 <code>↑</code> / <code>↓</code> 在建议之间切换。</li><li>按 <code>Enter</code> 确认并插入选中的命令。</li><li>按 <code>Esc</code> 或 <code>←</code>（左箭头）退出选择模式或关闭面板。</li></ol><table tabindex="0"><thead><tr><th>按键</th><th>操作</th></tr></thead><tbody><tr><td><code>→</code></td><td>进入选择模式</td></tr><tr><td><code>↑</code> / <code>↓</code></td><td>在建议之间切换</td></tr><tr><td><code>Enter</code></td><td>确认并插入选中的命令</td></tr><tr><td><code>Esc</code></td><td>关闭补全面板</td></tr><tr><td><code>←</code></td><td>退出选择模式</td></tr></tbody></table><h2 id="配置" tabindex="-1">配置 <a class="header-anchor" href="#配置" aria-label="Permalink to &quot;配置&quot;">​</a></h2><p>您可以在 <strong>设置 &gt; 扩展设置</strong> 中开启或关闭自动补全：</p><ul><li><strong>开启</strong>（推荐） -- 输入时显示补全建议。</li><li><strong>关闭</strong> -- 完全隐藏补全面板，手动输入命令。</li></ul><p>有关此设置的详细位置，请参阅 <a href="/docs/settings/extensions/">扩展设置</a>。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="补全面板没有出现" tabindex="-1">补全面板没有出现 <a class="header-anchor" href="#补全面板没有出现" aria-label="Permalink to &quot;补全面板没有出现&quot;">​</a></h3><ul><li>确认已在 <strong>设置 &gt; 扩展设置</strong> 中开启 <strong>自动补全</strong>。</li><li>至少输入一个字符并稍等片刻，等待建议出现。</li><li>如果面板仍未出现，请尝试重启终端会话。</li></ul><h3 id="ai-建议没有出现" tabindex="-1">AI 建议没有出现 <a class="header-anchor" href="#ai-建议没有出现" aria-label="Permalink to &quot;AI 建议没有出现&quot;">​</a></h3><ul><li>AI 建议需要网络连接。本地补全（历史记录和内置命令）在离线状态下仍可正常工作。</li><li>检查设置中是否已启用 AI 功能。</li></ul><h3 id="建议似乎不相关" tabindex="-1">建议似乎不相关 <a class="header-anchor" href="#建议似乎不相关" aria-label="Permalink to &quot;建议似乎不相关&quot;">​</a></h3><ul><li>命令补全会随着您的使用逐渐学习，历史记录越多建议越准确。</li><li>跨主机推荐可能会显示来自其他服务器的命令。如果建议不适用，忽略它并继续输入即可。</li></ul>',21),i=[d];function n(c,s,h,u,p,_){return a(),e("div",null,i)}const b=t(r,[["render",n]]);export{g as __pageData,b as default};
